import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import he from '../i18n/he.json';

export default function LoginPage() {
  const [phone, setPhone] = useState('');
  const [loading, setLoading] = useState(false);
  const [orders, setOrders] = useState(null);
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await axios.get('https://pizza-story-backend-u6n0.onrender.com/api/orders');
      const userOrders = res.data.filter((o) => o.phone === phone);
      localStorage.setItem('userPhone', phone);
      setOrders(userOrders);
    } catch (err) {
      alert('שגיאה בטעינת ההזמנות');
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    setOrders(null);
    setPhone('');
    localStorage.removeItem('userPhone');
  };

  if (orders !== null) {
    const totalSpent = orders.reduce((sum, o) => sum + (o.total || 0), 0);

    return (
      <div className="max-w-md mx-auto mt-10 p-6 bg-white rounded-lg shadow-lg">
        <div className="flex items-center justify-between mb-1">
          <h2 className="text-xl font-bold text-tomato">{he.order_history}</h2>
          <span className="text-sm text-gray-400" dir="ltr">{phone}</span>
        </div>
        <p className="text-sm text-gray-500 mb-4">
          {orders.length} הזמנות | סה"כ שולם: {totalSpent}₪
        </p>

        {orders.length === 0 ? (
          <p className="text-gray-400 text-center py-10">{he.no_history}</p>
        ) : (
          <div className="space-y-3">
            {orders.map((order, idx) => (
              <div key={idx} className="bg-orange-50 rounded-lg p-4 border border-crust">
                <div className="flex justify-between items-center mb-1">
                  <span className="font-bold text-tomato">{order.total}₪</span>
                  <span className="text-xs text-gray-400">
                    {order.createdAt
                      ? new Date(order.createdAt).toLocaleDateString('he-IL')
                      : ''}
                  </span>
                </div>
                <div className="text-sm text-gray-600">
                  {order.toppings && order.toppings.length > 0
                    ? order.toppings.join(', ')
                    : 'ללא תוספות'}
                </div>
                {order.address && (
                  <div className="text-xs text-gray-400 mt-1">{order.address}</div>
                )}
                {order.paymentMethod && (
                  <div className="text-xs text-gray-400 mt-0.5">
                    תשלום: {order.paymentMethod === 'cash' ? he.cash : he.credit}
                  </div>
                )}
              </div>
            ))}
          </div>
        )}

        <button
          onClick={() => navigate('/')}
          className="mt-5 w-full bg-tomato text-white py-2 rounded-lg font-bold hover:bg-red-700 transition"
        >
          {he.back_to_menu}
        </button>
        <button
          onClick={handleLogout}
          className="mt-2 w-full border border-gray-300 text-gray-500 py-2 rounded-lg hover:bg-gray-50 transition"
        >
          {he.logout}
        </button>
      </div>
    );
  }

  return (
    <form
      onSubmit={handleLogin}
      className="max-w-md mx-auto mt-10 p-6 bg-white rounded-lg shadow-lg"
    >
      <h2 className="text-2xl font-bold text-tomato mb-1 text-center">{he.app_title}</h2>
      <p className="text-gray-500 text-center mb-6">{he.phone_login}</p>

      <div className="mb-4">
        <label className="block mb-1 font-medium">{he.phone}</label>
        <input
          type="tel"
          value={phone}
          onChange={(e) => setPhone(e.target.value)}
          required
          placeholder="050-0000000"
          className="w-full border rounded-lg px-3 py-2 focus:outline-tomato text-center text-lg"
          dir="ltr"
        />
      </div>

      <button
        type="submit"
        disabled={loading}
        className="w-full bg-tomato text-white py-2 rounded-lg font-bold text-lg hover:bg-red-700 transition"
      >
        {loading ? 'טוען...' : he.login_btn}
      </button>
      <button
        type="button"
        onClick={() => navigate('/')}
        className="mt-3 w-full border border-gray-300 text-gray-500 py-2 rounded-lg hover:bg-gray-50 transition"
      >
        {he.back_to_menu}
      </button>
    </form>
  );
}
